INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, -416.5, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 3001100, 2.1, "2024/10/31 12:00:00", "ヤマト", 130011, 0.0, 100, 1, 3001, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, -416.5, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 3001101, 5.68, "2024/10/31 12:00:00", "ヤマト", 130011, 0.0, 101, 4, 3001, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, -416.5, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 3001102, 0.0, "2024/10/31 12:00:00", "ヤマト", 130011, 0.0, 102, 1, 3001, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, -416.5, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 3002100, 0.0, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 100, 1, 3002, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, -416.5, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 3002101, 0.0, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 101, 1, 3002, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, -416.5, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 3002102, 8.53, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 102, 5, 3002, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, -416.5, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 3002103, 5.67, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 103, 7, 3002, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, -416.5, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 3002104, 0.0, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 104, 1, 3002, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (3, -416.5, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 3002300, 0.0, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 300, 3, 3004, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (7, -416.5, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 3002400, 0.0, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 301, 7, 3005, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, -416.5, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 3003200, 4.4, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 200, 2, 3003, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (7, -416.5, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 3003201, 0.0, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 201, 7, 3003, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, -416.5, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 3003202, 5.6, "2024/10/31 12:00:00", "フブキ", 130211, 0.0, 202, 1, 3003, "2030/01/01 14:59:59");
